# Simple rule-based reasoning system
class SimpleExpertSystem:
    def __init__(self):
        self.knowledge_base = {
            'has_fever': False,
            'has_cough': False,
            'has_fatigue': False
        }
        self.rules = [
            ({'has_fever': True, 'has_cough': True}, 'Possible flu'),
            ({'has_fever': True, 'has_fatigue': True}, 'Possible viral infection'),
            ({'has_cough': True, 'has_fatigue': True}, 'Rest recommended')
        ]

    def set_symptom(self, symptom, value):
        if symptom in self.knowledge_base:
            self.knowledge_base[symptom] = value

    def reason(self):
        conclusions = []
        for conditions, conclusion in self.rules:
            if all(self.knowledge_base.get(k) == v for k, v in conditions.items()):
                conclusions.append(conclusion)
        return conclusions if conclusions else ['No diagnosis']

# Usage
system = SimpleExpertSystem()
system.set_symptom('has_fever', True)
system.set_symptom('has_cough', True)
print('Diagnosis:', system.reason())  # Output: ['Possible flu']

import java.util.*;

public class SimpleLearningAgent {
    private Map<String, Double> actionValues;
    private double learningRate = 0.1;

    public SimpleLearningAgent() {
        actionValues = new HashMap<>();
        actionValues.put("action_A", 0.5);
        actionValues.put("action_B", 0.5);
    }

    public String chooseAction() {
        // Simple greedy choice
        return actionValues.entrySet().stream()
            .max(Map.Entry.comparingByValue())
            .map(Map.Entry::getKey)
            .orElse("action_A");
    }

    public void learn(String action, double reward) {
        double oldValue = actionValues.get(action);
        double newValue = oldValue + learningRate * (reward - oldValue);
        actionValues.put(action, newValue);
        System.out.printf("Updated %s: %.2f -> %.2f%n", action, oldValue, newValue);
    }

    public static void main(String[] args) {
        SimpleLearningAgent agent = new SimpleLearningAgent();

        // Simulate learning from experience
        agent.learn("action_A", 1.0);  // Positive reward
        agent.learn("action_B", 0.0);  // No reward
        agent.learn("action_A", 1.0);  // Another positive reward

        System.out.println("Best action: " + agent.chooseAction());
    }
}

#include <stdio.h>

// Simple perceptron for AND gate recognition
float weights[3] = {0.5, 0.5, -0.7}; // w1, w2, bias
float learning_rate = 0.1;

int predict(int x1, int x2) {
    float sum = x1 * weights[0] + x2 * weights[1] + weights[2];
    return sum >= 0 ? 1 : 0;
}

void train(int x1, int x2, int target) {
    int output = predict(x1, x2);
    int error = target - output;

    weights[0] += learning_rate * error * x1;
    weights[1] += learning_rate * error * x2;
    weights[2] += learning_rate * error;
}

int main() {
    // Training data for AND gate
    int inputs[][2] = {{0,0}, {0,1}, {1,0}, {1,1}};
    int targets[] = {0, 0, 0, 1};

    // Training loop
    for (int epoch = 0; epoch < 100; epoch++) {
        for (int i = 0; i < 4; i++) {
            train(inputs[i][0], inputs[i][1], targets[i]);
        }
    }

    // Test
    printf("AND Gate Recognition:\n");
    for (int i = 0; i < 4; i++) {
        printf("%d AND %d = %d\n", inputs[i][0], inputs[i][1], 
               predict(inputs[i][0], inputs[i][1]));
    }
    return 0;
}
